sql:
SELECT movie_id, COUNT(actor_id) AS total_actors
FROM movie_actors
GROUP BY movie_id;

SELECT title, revenue_millions, RANK() OVER (ORDER BY revenue_millions DESC) AS revenue_rank
FROM movies
LIMIT 5;

SELECT total_votes
FROM votes
WHERE movie_id = (SELECT movie_id FROM movies WHERE title = 'specific movie title');

SELECT title
FROM movies
WHERE metascore < (SELECT AVG(metascore) FROM movies);

external_knowledge:
- "Whispers from the judging whispers of the critics" metaphorically refers to ratings from critics;
- "Cinematic gems" metaphorically refers to movies;
- The top 10 movies with the highest number of critic ratings are considered those that have attracted the most critical attention.
